import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  ArrowRightIcon,
  CheckBadgeIcon,
  ChartBarIcon,
  ChatBubbleLeftRightIcon,
  ShieldCheckIcon,
  UserGroupIcon,
  DocumentTextIcon,
  GlobeAltIcon,
  ClockIcon,
  StarIcon,
  ChevronRightIcon,
  PlayIcon,
  SparklesIcon,
  FingerPrintIcon,
  MapPinIcon,
} from '@heroicons/react/24/outline';
import { Link } from 'react-router-dom';
import CountUp from 'react-countup';
import { useInView } from 'react-intersection-observer';

/* ===============================
   IMAGE DATA
================================= */

const IMGS = {
  hero: [
    {
      name: 'Sri Lanka Parliament',
      region: 'Sri Jayawardenepura Kotte',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/1280px-Sri_Lanka_Parliament_2.jpg',
      fb: 'https://picsum.photos/seed/parliament/1600/900',
    },
    {
      name: 'Presidential Secretariat',
      region: 'Colombo',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Presidential_Secretariat%2C_Colombo.jpg/1280px-Presidential_Secretariat%2C_Colombo.jpg',
      fb: 'https://picsum.photos/seed/presidsec/1600/900',
    },
    {
      name: 'Supreme Court of Sri Lanka',
      region: 'Colombo',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Supreme_Court_of_Sri_Lanka.jpg/1280px-Supreme_Court_of_Sri_Lanka.jpg',
      fb: 'https://picsum.photos/seed/court/1600/900',
    },
    {
      name: 'Independence Memorial Hall',
      region: 'Colombo',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/1280px-Independence_Memorial_Hall_Sri_Lanka.jpg',
      fb: 'https://picsum.photos/seed/independence/1600/900',
    },
  ],

  strip: [
    {
      name: 'Parliament',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/640px-Sri_Lanka_Parliament_2.jpg',
      fb: 'https://picsum.photos/seed/s1/400/250',
    },
    {
      name: 'Presidential Secretariat',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Presidential_Secretariat%2C_Colombo.jpg/640px-Presidential_Secretariat%2C_Colombo.jpg',
      fb: 'https://picsum.photos/seed/s2/400/250',
    },
    {
      name: 'Supreme Court',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Supreme_Court_of_Sri_Lanka.jpg/640px-Supreme_Court_of_Sri_Lanka.jpg',
      fb: 'https://picsum.photos/seed/s3/400/250',
    },
    {
      name: 'Independence Hall',
      src: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/640px-Independence_Memorial_Hall_Sri_Lanka.jpg',
      fb: 'https://picsum.photos/seed/s4/400/250',
    },
  ],
};

const POLITICIANS = [
  {
    name: 'Anura Kumara Dissanayake',
    role: 'President of Sri Lanka',
    party: 'NPP',
    promisesKept: 72,
    totalPromises: 102,
    rating: 70.6,
    trend: '+9.4%',
    color: '#800000',
    photo:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2c/Anura_Kumara_Dissanayake.jpg/400px-Anura_Kumara_Dissanayake.jpg',
    photoFb: 'https://picsum.photos/seed/anura/400/500',
    place: 'Presidential Secretariat, Colombo',
    placeImg:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Presidential_Secretariat%2C_Colombo.jpg/640px-Presidential_Secretariat%2C_Colombo.jpg',
    placeImgFb: 'https://picsum.photos/seed/anura-place/640/400',
  },
  {
    name: 'Sajith Premadasa',
    role: 'Leader of the Opposition',
    party: 'SJB',
    promisesKept: 67,
    totalPromises: 95,
    rating: 70.5,
    trend: '+3.8%',
    color: '#1B4D3E',
    photo:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/Sajith_Premadasa_%28cropped%29.jpg/400px-Sajith_Premadasa_%28cropped%29.jpg',
    photoFb: 'https://picsum.photos/seed/sajith/400/500',
    place: 'Independence Memorial Hall, Colombo',
    placeImg:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/640px-Independence_Memorial_Hall_Sri_Lanka.jpg',
    placeImgFb: 'https://picsum.photos/seed/sajith-place/640/400',
  },
  {
    name: 'Ranil Wickremesinghe',
    role: 'Former President',
    party: 'UNP',
    promisesKept: 85,
    totalPromises: 120,
    rating: 70.8,
    trend: '+2.1%',
    color: '#FF6B35',
    photo:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Ranil_Wickremesinghe_2017.jpg/400px-Ranil_Wickremesinghe_2017.jpg',
    photoFb: 'https://picsum.photos/seed/ranil/400/500',
    place: 'Sri Lanka Parliament, Kotte',
    placeImg:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/640px-Sri_Lanka_Parliament_2.jpg',
    placeImgFb: 'https://picsum.photos/seed/ranil-place/640/400',
  },
];

const NEWS = [
  {
    title: 'Parliamentary debate continues on key national reforms',
    source: 'Political Desk',
    time: '2 hours ago',
    category: 'Governance',
    img: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Sri_Lanka_Parliament_2.jpg/640px-Sri_Lanka_Parliament_2.jpg',
    imgFb: 'https://picsum.photos/seed/news1/500/300',
  },
  {
    title: 'Opposition highlights economic concerns in Colombo',
    source: 'Civic Monitor',
    time: '5 hours ago',
    category: 'Economy',
    img: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Independence_Memorial_Hall_Sri_Lanka.jpg/640px-Independence_Memorial_Hall_Sri_Lanka.jpg',
    imgFb: 'https://picsum.photos/seed/news2/500/300',
  },
  {
    title: 'Judicial reform remains a key public discussion topic',
    source: 'Citizen Watch',
    time: '1 day ago',
    category: 'Law',
    img: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Supreme_Court_of_Sri_Lanka.jpg/640px-Supreme_Court_of_Sri_Lanka.jpg',
    imgFb: 'https://picsum.photos/seed/news3/500/300',
  },
];

const TESTIMONIALS = [
  {
    name: 'Nimal Perera',
    role: 'Colombo Resident',
    img: 'https://randomuser.me/api/portraits/men/11.jpg',
    comment: 'This platform clearly shows which promises are being kept and which are not.',
    rating: 5,
  },
  {
    name: 'Kamala Silva',
    role: 'Community Volunteer',
    img: 'https://randomuser.me/api/portraits/women/21.jpg',
    comment: 'The visual design and transparent data make this very useful for citizens.',
    rating: 5,
  },
  {
    name: 'Dr. Asanka Weerasinghe',
    role: 'University Lecturer',
    img: 'https://randomuser.me/api/portraits/men/32.jpg',
    comment: 'A strong concept for democratic transparency and public participation.',
    rating: 5,
  },
];

const STATS = [
  { id: 1, value: 225, label: 'Politicians Tracked', icon: UserGroupIcon, suffix: '+' },
  { id: 2, value: 1247, label: 'Promises Made', icon: DocumentTextIcon, suffix: '+' },
  { id: 3, value: 856, label: 'Promises Kept', icon: CheckBadgeIcon, suffix: '+' },
  { id: 4, value: 3452, label: 'Citizen Reports', icon: ChatBubbleLeftRightIcon, suffix: '+' },
];

const FEATURES = [
  {
    icon: ShieldCheckIcon,
    title: 'Promise Tracking',
    desc: 'Track political promises with status updates, supporting evidence, and public accountability.',
    gradient: 'from-blue-500 to-cyan-500',
    stat: '95% Accuracy',
    delay: 0,
  },
  {
    icon: ChartBarIcon,
    title: 'Performance Analytics',
    desc: 'View completion rates, politician ratings, and promise fulfillment history.',
    gradient: 'from-purple-500 to-pink-500',
    stat: 'Live Updates',
    delay: 0.1,
  },
  {
    icon: GlobeAltIcon,
    title: 'News Integration',
    desc: 'Connect political news and developments with ongoing promises and public feedback.',
    gradient: 'from-orange-500 to-red-500',
    stat: '24/7 Updates',
    delay: 0.2,
  },
  {
    icon: ChatBubbleLeftRightIcon,
    title: 'Citizen Feedback',
    desc: 'Let citizens contribute reports, opinions, and evidence for better transparency.',
    gradient: 'from-green-500 to-emerald-500',
    stat: '10k+ Reviews',
    delay: 0.3,
  },
];

/* ===============================
   HELPERS
================================= */

const Img = ({ src, fb, alt = '', className = '', style = {} }) => {
  const [err, setErr] = useState(false);

  return (
    <img
      src={err ? fb : src}
      alt={alt}
      referrerPolicy="no-referrer"
      crossOrigin="anonymous"
      onError={() => setErr(true)}
      className={className}
      style={style}
    />
  );
};

const SectionBg = ({ src, fb, opacity = 0.07, overlayClass = 'bg-white/93 dark:bg-gray-900/93' }) => (
  <div className="absolute inset-0 overflow-hidden pointer-events-none">
    <Img src={src} fb={fb} alt="" className="w-full h-full object-cover" style={{ opacity }} />
    <div className={`absolute inset-0 ${overlayClass}`} />
  </div>
);

/* ===============================
   HERO
================================= */

const HeroSlideshow = () => {
  const [cur, setCur] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCur((prev) => (prev + 1) % IMGS.hero.length);
    }, 5000);

    return () => clearInterval(timer);
  }, []);

  return (
    <div className="absolute inset-0 z-0">
      {IMGS.hero.map((slide, i) => (
        <AnimatePresence key={i}>
          {i === cur && (
            <motion.div
              key={`hero-${i}`}
              className="absolute inset-0"
              initial={{ opacity: 0, scale: 1.05 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.4, ease: 'easeInOut' }}
            >
              <Img
                src={slide.src}
                fb={slide.fb}
                alt={slide.name}
                className="w-full h-full object-cover"
              />
            </motion.div>
          )}
        </AnimatePresence>
      ))}

      <div className="absolute inset-0 bg-gradient-to-b from-black/70 via-black/55 to-orange-950/80 z-10" />
      <div className="absolute inset-0 bg-gradient-to-r from-black/20 via-transparent to-black/20 z-10" />

      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-20 flex flex-col items-center gap-3">
        <AnimatePresence mode="wait">
          <motion.div
            key={`label-${cur}`}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -6 }}
            transition={{ duration: 0.45 }}
            className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-black/30 backdrop-blur-md border border-white/20"
          >
            <MapPinIcon className="w-4 h-4 text-orange-300" />
            <span className="text-white text-sm font-semibold">{IMGS.hero[cur].name}</span>
            <span className="text-white/60 text-xs hidden sm:inline">· {IMGS.hero[cur].region}</span>
          </motion.div>
        </AnimatePresence>

        <div className="flex items-center gap-2">
          {IMGS.hero.map((_, i) => (
            <button
              key={i}
              onClick={() => setCur(i)}
              aria-label={`Slide ${i + 1}`}
              style={{
                width: i === cur ? 26 : 8,
                height: 8,
                borderRadius: 4,
                border: 'none',
                cursor: 'pointer',
                background: i === cur ? '#F59E0B' : 'rgba(255,255,255,0.35)',
                transition: 'all 0.3s ease',
              }}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

/* ===============================
   LANDMARK STRIP
================================= */

const LandmarkStrip = () => {
  const doubled = [...IMGS.strip, ...IMGS.strip];

  return (
    <div className="relative overflow-hidden bg-gradient-to-r from-red-950 via-orange-950 to-red-950 py-1">
      <motion.div
        className="flex"
        style={{ width: 'max-content' }}
        animate={{ x: ['0%', '-50%'] }}
        transition={{ duration: 30, ease: 'linear', repeat: Infinity }}
      >
        {doubled.map((item, i) => (
          <div
            key={i}
            className="relative flex-shrink-0 overflow-hidden"
            style={{ width: 240, height: 140, margin: '0 3px' }}
          >
            <Img
              src={item.src}
              fb={item.fb}
              alt={item.name}
              className="w-full h-full object-cover hover:scale-105 transition-transform duration-500"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/65 via-transparent to-transparent" />
            <div className="absolute bottom-2.5 left-3 flex items-center gap-1">
              <MapPinIcon className="w-3 h-3 text-orange-300" />
              <span className="text-white text-xs font-medium">{item.name}</span>
            </div>
          </div>
        ))}
      </motion.div>
    </div>
  );
};

/* ===============================
   STATS
================================= */

const StatCards = () => {
  const [ref, inView] = useInView({ triggerOnce: true, threshold: 0.1 });

  return (
    <div ref={ref} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      {STATS.map((s, i) => (
        <motion.div
          key={s.id}
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ delay: i * 0.1 }}
          whileHover={{ y: -5 }}
          className="bg-white/96 dark:bg-gray-800/96 backdrop-blur-sm rounded-2xl shadow-xl p-6 border border-gray-200 dark:border-gray-700 hover:shadow-2xl transition-all"
        >
          <div className="flex items-center justify-between mb-4">
            <div className="w-12 h-12 rounded-full bg-orange-100 dark:bg-orange-500/20 flex items-center justify-center">
              <s.icon className="w-6 h-6 text-orange-500" />
            </div>
            <SparklesIcon className="w-5 h-5 text-yellow-500 animate-pulse" />
          </div>

          <div className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
            {inView ? <CountUp end={s.value} duration={2.5} /> : 0}
            {s.suffix}
          </div>

          <div className="text-gray-600 dark:text-gray-400 text-sm">{s.label}</div>
        </motion.div>
      ))}
    </div>
  );
};

/* ===============================
   MAIN COMPONENT
================================= */

const Home = () => {
  const [hoveredCard, setHoveredCard] = useState(null);

  return (
    <div className="overflow-hidden">
