      </section>

      {/* FEATURES */}
      <section className="py-20 relative overflow-hidden">
        <SectionBg
          src={IMGS.hero[3].src}
          fb={IMGS.hero[3].fb}
          opacity={0.06}
          overlayClass="bg-gradient-to-br from-gray-50/95 to-white/95 dark:from-gray-900/95 dark:to-gray-800/95"
        />
        <div className="container mx-auto px-4 relative z-10">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
